using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class InMemoryCatalogService : ICatalogService
{
    private readonly List<Course> _courses;

    public InMemoryCatalogService()
    {
        _courses =
        [
            new()
            {
                Id = 1, Code = "CS 101", Title = "Introduction to Computer Science",
                Description = "A broad overview of computer science covering algorithms, data structures, software engineering, and computational theory. Students will complete hands-on programming projects using Python.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentCode = "CS", DepartmentName = "Computer Science",
                Instructor = new() { Name = "Dr. Ada Lovelace", Title = "Professor", Email = "alovelace@university.edu", Bio = "Dr. Lovelace has 15 years of experience in computer science education and specializes in algorithms and programming language theory." },
                IsFeatured = true
            },
            new()
            {
                Id = 2, Code = "CS 301", Title = "Database Systems",
                Description = "Fundamentals of relational database design, SQL, normalization, indexing, and transaction management. Includes a semester-long project building a full database application.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", DepartmentCode = "CS", DepartmentName = "Computer Science",
                Instructor = new() { Name = "Dr. Edgar Codd", Title = "Associate Professor", Email = "ecodd@university.edu", Bio = "Dr. Codd is a database researcher with publications in query optimization and distributed data systems." }
            },
            new()
            {
                Id = 3, Code = "CS 410", Title = "Machine Learning",
                Description = "Supervised and unsupervised learning, neural networks, decision trees, and model evaluation. Students apply techniques to real-world datasets using Python and scikit-learn.",
                Credits = 4, Schedule = "Mon/Wed 2:00–3:15 PM", DepartmentCode = "CS", DepartmentName = "Computer Science",
                Instructor = new() { Name = "Dr. Alan Turing", Title = "Professor", Email = "aturing@university.edu", Bio = "Dr. Turing is an award-winning researcher in artificial intelligence and computational theory with over 50 publications." },
                IsFeatured = true
            },
            new()
            {
                Id = 4, Code = "MATH 201", Title = "Linear Algebra",
                Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and engineering. Emphasizes both theory and computational methods.",
                Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentCode = "MATH", DepartmentName = "Mathematics",
                Instructor = new() { Name = "Dr. Emmy Noether", Title = "Professor", Email = "enoether@university.edu", Bio = "Dr. Noether is a mathematician known for her work in abstract algebra and has received multiple teaching excellence awards." }
            },
            new()
            {
                Id = 5, Code = "MATH 301", Title = "Probability and Statistics",
                Description = "Probability distributions, hypothesis testing, confidence intervals, regression analysis, and Bayesian methods. Applications drawn from science and engineering.",
                Credits = 3, Schedule = "Tue/Thu 10:00–11:15 AM", DepartmentCode = "MATH", DepartmentName = "Mathematics",
                Instructor = new() { Name = "Dr. Carl Gauss", Title = "Associate Professor", Email = "cgauss@university.edu", Bio = "Dr. Gauss specializes in applied statistics and has consulted for government and industry on large-scale data analysis projects." },
                IsFeatured = true
            },
            new()
            {
                Id = 6, Code = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions where students conduct experiments and analyze data.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", DepartmentCode = "PHYS", DepartmentName = "Physics",
                Instructor = new() { Name = "Dr. Richard Feynman", Title = "Professor", Email = "rfeynman@university.edu", Bio = "Dr. Feynman is a renowned physicist and educator who brings complex topics to life through engaging lectures and demonstrations." }
            },
            new()
            {
                Id = 7, Code = "PHYS 301", Title = "Quantum Mechanics",
                Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory. Prerequisites: PHYS 101, MATH 201.",
                Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", DepartmentCode = "PHYS", DepartmentName = "Physics",
                Instructor = new() { Name = "Dr. Niels Bohr", Title = "Professor", Email = "nbohr@university.edu", Bio = "Dr. Bohr has led groundbreaking research in atomic physics and mentors graduate students in theoretical physics." }
            },
            new()
            {
                Id = 8, Code = "ENG 110", Title = "Academic Writing",
                Description = "Develops skills in argumentation, research-based writing, and critical reading. Students produce a portfolio of essays across multiple genres.",
                Credits = 3, Schedule = "Mon/Wed 1:00–2:15 PM", DepartmentCode = "ENG", DepartmentName = "English",
                Instructor = new() { Name = "Dr. Maya Angelou", Title = "Professor", Email = "mangelou@university.edu", Bio = "Dr. Angelou is an accomplished writer and educator who has published extensively on rhetoric and composition pedagogy." }
            },
            new()
            {
                Id = 9, Code = "ENG 250", Title = "World Literature",
                Description = "A survey of major literary works from diverse cultures and time periods. Examines themes of identity, power, and human experience through close reading and discussion.",
                Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", DepartmentCode = "ENG", DepartmentName = "English",
                Instructor = new() { Name = "Dr. Chinua Achebe", Title = "Associate Professor", Email = "cachebe@university.edu", Bio = "Dr. Achebe is a literary scholar specializing in postcolonial literature and has taught courses on African and world literature for over a decade." },
                IsFeatured = true
            },
            new()
            {
                Id = 10, Code = "HIST 101", Title = "World History to 1500",
                Description = "A survey of human civilizations from prehistory through the late Middle Ages, covering political, social, and cultural developments across regions.",
                Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentCode = "HIST", DepartmentName = "History",
                Instructor = new() { Name = "Dr. Howard Zinn", Title = "Professor", Email = "hzinn@university.edu", Bio = "Dr. Zinn is a historian and author who focuses on social movements and encourages students to examine history from multiple perspectives." }
            },
        ];
    }

    public IReadOnlyList<Department> GetDepartments()
    {
        return _courses
            .GroupBy(c => new { c.DepartmentCode, c.DepartmentName })
            .Select(g => new Department
            {
                Code = g.Key.DepartmentCode,
                Name = g.Key.DepartmentName,
                CourseCount = g.Count()
            })
            .OrderBy(d => d.Name)
            .ToList();
    }

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, string? departmentCode = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
        {
            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.DepartmentCode).ThenBy(c => c.Code).ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses()
    {
        return _courses.Where(c => c.IsFeatured).ToList();
    }

    public Course? GetCourseById(int id)
    {
        return _courses.FirstOrDefault(c => c.Id == id);
    }
}

