arguments.file_text:
@using UniversityCourseCatalog.Models

<div class="card h-100 shadow-sm">
    <div class="card-body">
        <span class="badge bg-primary mb-2">@Course.DepartmentName</span>
        <h5 class="card-title">@Course.Code — @Course.Title</h5>
        <p class="card-text text-muted">@Course.Credits credits · @Course.Instructor.Name</p>
        <p class="card-text">@Truncate(Course.Description, 120)</p>
    </div>
    <div class="card-footer bg-transparent">
        <a href="courses/@Course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public required Course Course { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "…");
}

@using UniversityCourseCatalog.Models

<div class="card h-100 border-primary shadow">
    <div class="card-body">
        <span class="badge bg-warning text-dark mb-2">⭐ Featured</span>
        <span class="badge bg-primary mb-2">@Course.DepartmentName</span>
        <h5 class="card-title">@Course.Code — @Course.Title</h5>
        <p class="card-text text-muted">@Course.Credits credits · @Course.Schedule</p>
        <p class="card-text">@Truncate(Course.Description, 150)</p>
    </div>
    <div class="card-footer bg-transparent">
        <a href="courses/@Course.Id" class="btn btn-primary btn-sm">View Details</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public required Course Course { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "…");
}

