@page "/"
@using UniversityCourseCatalog.Components.Shared
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-5 fw-bold">University Course Catalog</h1>
    <p class="lead text-muted">Browse departments, explore courses, and submit enrollment requests.</p>
    <a href="courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="enroll" class="btn btn-outline-secondary btn-lg">Enroll Now</a>
</div>

<section class="mb-5">
    <h2 class="mb-3">Featured Courses</h2>
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var course in _featured)
        {
            <div class="col">
                <FeaturedCourseCard Course="course" />
            </div>
        }
    </div>
</section>

<section>
    <h2 class="mb-3">Departments</h2>
    <div class="row row-cols-2 row-cols-md-3 row-cols-lg-5 g-3">
        @foreach (var dept in _departments)
        {
            <div class="col">
                <DepartmentLinkCard Department="dept" />
            </div>
        }
    </div>
</section>

@code {
    private IReadOnlyList<Models.Course> _featured = [];
    private IReadOnlyList<Models.Department> _departments = [];

    protected override void OnInitialized()
    {
        _featured = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

arguments.file_text:
@page "/courses"
@using UniversityCourseCatalog.Components.Shared
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

@rendermode InteractiveServer

<PageTitle>Courses — University Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<CourseFilters SearchTerm="@_searchTerm"
              SelectedDepartment="@_selectedDepartment"
              Departments="_departments"
              SearchTermChanged="OnSearchTermChanged"
              SelectedDepartmentChanged="OnDepartmentChanged" />

@if (_filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @_filteredCourses.Count course@(_filteredCourses.Count != 1 ? "s" : "")</p>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in _filteredCourses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
}

@code {
    private string _searchTerm = "";
    private string _selectedDepartment = "";
    private IReadOnlyList<Models.Department> _departments = [];
    private IReadOnlyList<Models.Course> _filteredCourses = [];

    [SupplyParameterFromQuery(Name = "dept")]
    private string? InitialDepartment { get; set; }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        if (!string.IsNullOrWhiteSpace(InitialDepartment))
        {
            _selectedDepartment = InitialDepartment;
        }
        ApplyFilters();
    }

    private void OnSearchTermChanged(string term)
    {
        _searchTerm = term;
        ApplyFilters();
    }

    private void OnDepartmentChanged(string dept)
    {
        _selectedDepartment = dept;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        _filteredCourses = CatalogService.GetCourses(_searchTerm, _selectedDepartment);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Components.Shared
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found") — University Course Catalog</PageTitle>

@if (_course is null)
{
    <div class="alert alert-warning">
        <h4>Course not found</h4>
        <p>The course you're looking for doesn't exist. <a href="courses">Browse all courses</a>.</p>
    </div>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@_course.Code — @_course.Title</h1>
            <span class="badge bg-primary mb-3">@_course.DepartmentName</span>

            <p class="lead">@_course.Description</p>

            <table class="table table-bordered w-auto mt-4">
                <tbody>
                    <tr><th scope="row">Credits</th><td>@_course.Credits</td></tr>
                    <tr><th scope="row">Schedule</th><td>@_course.Schedule</td></tr>
                    <tr><th scope="row">Department</th><td>@_course.DepartmentName</td></tr>
