@page "/"
@using UniversityCourseCatalog.Components.Shared
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-5 fw-bold">University Course Catalog</h1>
    <p class="lead text-muted">Browse departments, explore courses, and submit enrollment requests.</p>
    <a href="courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="enroll" class="btn btn-outline-secondary btn-lg">Enroll Now</a>
</div>

<section class="mb-5">
    <h2 class="mb-3">Featured Courses</h2>
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var course in _featured)
        {
            <div class="col">
                <FeaturedCourseCard Course="course" />
            </div>
        }
    </div>
</section>

<section>
    <h2 class="mb-3">Departments</h2>
    <div class="row row-cols-2 row-cols-md-3 row-cols-lg-5 g-3">
        @foreach (var dept in _departments)
        {
            <div class="col">
                <DepartmentLinkCard Department="dept" />
            </div>
        }
    </div>
</section>

@code {
    private IReadOnlyList<Models.Course> _featured = [];
    private IReadOnlyList<Models.Department> _departments = [];

    protected override void OnInitialized()
    {
        _featured = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

toolArgs.file_text:
@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Components.Shared
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found") — University Course Catalog</PageTitle>

@if (_course is null)
{
    <div class="alert alert-warning">
        <h4>Course not found</h4>
        <p>The course you're looking for doesn't exist. <a href="courses">Browse all courses</a>.</p>
    </div>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@_course.Code — @_course.Title</h1>
            <span class="badge bg-primary mb-3">@_course.DepartmentName</span>

            <p class="lead">@_course.Description</p>

            <table class="table table-bordered w-auto mt-4">
                <tbody>
                    <tr><th scope="row">Credits</th><td>@_course.Credits</td></tr>
                    <tr><th scope="row">Schedule</th><td>@_course.Schedule</td></tr>
                    <tr><th scope="row">Department</th><td>@_course.DepartmentName</td></tr>
                </tbody>
            </table>

            <a href="enroll?courseId=@_course.Id" class="btn btn-primary mt-3">Request Enrollment</a>
        </div>

        <div class="col-lg-4 mt-4 mt-lg-0">
            <h4 class="mb-3">Instructor</h4>
            <InstructorBio Instructor="_course.Instructor" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Models.Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourseById(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for
           <strong>@_selectedCourseTitle</strong> has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation via your university email.</p>
    </div>
    <a href="enroll" class="btn btn-outline-primary">Submit Another Request</a>
}
else
{
    <div class="row">
        <div class="col-lg-6">
            <EditForm method="post" Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
                <DataAnnotationsValidator />
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="_model.FullName" />
                    <ValidationMessage For="() => _model.FullName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" />
                    <ValidationMessage For="() => _model.StudentId" />
                    <div class="form-text">6–10 uppercase letters or digits (e.g., STU12345).</div>
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    private int? PreselectedCourseId { get; set; }

    private IReadOnlyList<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseTitle = "";

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (PreselectedCourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourseById(_model.CourseId);
        _selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        _submitted = true;
    }
}

